              </button>
            </div>
          </div>
        </form>
        {showSuggestions && !loading && (
          <div className="absolute top-full left-0 right-0 bg-white border-2 border-stone-200 shadow-2xl z-20 rounded-b-sm overflow-hidden animate-in fade-in slide-in-from-top-2">
             {suggestions.map((s, idx) => (
               <button key={idx} onMouseDown={(e) => e.preventDefault()} onClick={() => { setQuery(s.term); handleSearch(s.term); }} className={`w-full text-left px-10 py-6 border-b border-stone-100 last:border-0 flex items-center justify-between transition-colors ${selectedIndex === idx ? 'bg-stone-50' : 'hover:bg-stone-50/50'}`}>
