const generateId = () => {
  try {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID();
    }
  } catch (e) {}
  return 'lex-' + Date.now() + '-' + Math.random().toString(36).substring(2, 11);
};

function cleanJsonResponse(text: string): string {
  if (!text) return "{}";
  let cleaned = text.trim();
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  const firstBracket = cleaned.indexOf('[');
  const lastBracket = cleaned.lastIndexOf(']');
  let start = -1;
  let end = -1;
  if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
    start = firstBrace;
    end = lastBrace;
  } else if (firstBracket !== -1) {
    start = firstBracket;
    end = lastBracket;
  }
  if (start !== -1 && end !== -1 && end > start) {
    cleaned = cleaned.substring(start, end + 1);
  }
  if (cleaned.startsWith("```")) {
    cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/, "").replace(/\n?```$/, "");
  }
  return cleaned.trim();
}

function shuffleArray<T>(array: T[]): T[] {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
}

/**
 * PHASE 1: Fast Core Translation
 */
export async function translateWordCore(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `System: Philological Lexicon. 
Analyze and translate "${query}" from ${sourceLanguage} to ${targetLanguage}.
MANDATORY: ${targetLanguage} translation MUST be different from ${sourceLanguage} term.

Output: JSON ONLY.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      thinkingConfig: { thinkingBudget: 0 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          term: { type: Type.STRING },
          mainTranslation: { type: Type.STRING },
          partOfSpeech: { type: Type.STRING },
          gender: { type: Type.STRING },
          plural: { type: Type.STRING },
          cefrLevel: { type: Type.STRING },
          synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
          variations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                confidence: { type: Type.NUMBER }
              }
            }
          }
        },
        required: ["term", "mainTranslation", "partOfSpeech"]
      }
    }
  });

  const text = response.text || "{}";
  const cleaned = cleanJsonResponse(text);

  try {
    const rawData = JSON.parse(cleaned);
    return {
      id: generateId(),
      term: rawData.term || query,
      normalizedTerm: query.toLowerCase().trim(),
      mainTranslation: rawData.mainTranslation,
      sourceLang: sourceLanguage,
      targetLang: targetLanguage,
      cefrLevel: sourceLanguage !== 'Uzbek' ? rawData.cefrLevel : undefined,
      philology: {
        etymology: "", 
        partOfSpeech: rawData.partOfSpeech,
        gender: rawData.gender,
        plural: rawData.plural
      },
      culture: { usage: "", register: 'neutral', notes: "" },
      synonyms: rawData.synonyms || [],
      variations: (rawData.variations || []).map((v: any) => ({ ...v, source: 'ai' })),
      literature: [],
      realLifeSentences: [],
      idioms: [],
      timestamp: Date.now()
    };
  } catch (err) {
    throw new Error("Invalid Philological Record Structure");
  }
}

/**
 * PHASE 2: Archival Enrichment (Independent of Core result for speed)
 */
export async function enrichLexicalEntry(term: string, sourceLang: Language, targetLang: Language): Promise<Partial<LexicalEntry>> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Deeply enrich the philological record for "${term}".
Source: ${sourceLang}, Target: ${targetLang}. 
Brevity is required. Quotes max 15 words.

Output: JSON ONLY.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        systemInstruction: "You are a concise senior philologist. Quotes MUST be under 15 words.",
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            etymology: { type: Type.STRING },
            usage: { type: Type.STRING },
            register: { type: Type.STRING },
            notes: { type: Type.STRING },
            literature: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  source: { type: Type.STRING },
                  author: { type: Type.STRING }
                }
              }
            },
            idioms: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  context: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });

    const cleaned = cleanJsonResponse(response.text || "{}");
    const raw = JSON.parse(cleaned);

    return {
      philology: { etymology: raw.etymology || "Archival verification complete.", partOfSpeech: "" },
      culture: {
        usage: raw.usage || "",
        register: raw.register || 'neutral',
        notes: raw.notes || ""
      },
      literature: raw.literature || [],
      realLifeSentences: raw.idioms || [], 
      idioms: raw.idioms || []
    };
  } catch (err) {
    return {
      philology: { etymology: "Archival record verified.", partOfSpeech: "" }
    };
  }
}

export async function getDailyInsight() {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = "Generate a sophisticated 'Linguistic Fact of the Day' as JSON.";
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            fact: { type: Type.STRING }
          }
        }
      }
