import React, { useState, useEffect, useRef } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWordCore, enrichLexicalEntry } from '../services/gemini';
import { speak, resumeAudioContext } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import { triggerHaptic } from '../services/telegram';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS',
  Arabic: 'ARA'
};

const LANGUAGES_LIST: Language[] = ['German', 'Uzbek', 'English', 'Russian', 'Arabic'];

const normalizeQuery = (text: string, lang: Language): string => {
  if (!text) return "";
  let res = text.trim().toLowerCase();
  res = res
    .replace(/[\u2018\u2019\u201A\u201B\u2032\u2035]/g, "'") 
    .replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"')
    .replace(/\u2013/g, "-")
    .replace(/\u2014/g, "--")
    .replace(/\u00A0/g, " ");

  if (lang === 'German') {
    res = res.replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`‘]/g, "'");
  }
  return res.trim();
};

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  selectedEntry,
  onEntryClick,
  onStartArena
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>(() => {
    const saved = localStorage.getItem('lexSourceLang');
    return (LANGUAGES_LIST.includes(saved as Language) ? (saved as Language) : 'German');
  });
  const [targetLang, setTargetLang] = useState<Language>(() => {
    const saved = localStorage.getItem('lexTargetLang');
    return (LANGUAGES_LIST.includes(saved as Language) ? (saved as Language) : 'Uzbek');
  });

  const [loading, setLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [voiceSupported, setVoiceSupported] = useState(true);
  const [voiceStatusMsg, setVoiceStatusMsg] = useState<string | null>(null);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [searchError, setSearchError] = useState<string | null>(null);

  const inputRef = useRef<HTMLInputElement>(null);

  // Prevent same-language translation pairs automatically
  const updateSourceLang = (l: Language) => {
    if (l === targetLang) {
      const next = LANGUAGES_LIST.find(lang => lang !== l) || 'Uzbek';
      setTargetLang(next as Language);
      localStorage.setItem('lexTargetLang', next);
    }
    setSourceLang(l);
    localStorage.setItem('lexSourceLang', l);
    triggerHaptic('light');
  };

  const updateTargetLang = (l: Language) => {
    if (l === sourceLang) {
      const next = LANGUAGES_LIST.find(lang => lang !== l) || 'German';
      setSourceLang(next as Language);
      localStorage.setItem('lexSourceLang', next);
    }
    setTargetLang(l);
    localStorage.setItem('lexTargetLang', l);
    triggerHaptic('light');
  };

  const swapLanguages = () => {
    const prevSource = sourceLang;
    const prevTarget = targetLang;
    setSourceLang(prevTarget);
    setTargetLang(prevSource);
    localStorage.setItem('lexSourceLang', prevTarget);
    localStorage.setItem('lexTargetLang', prevSource);
    triggerHaptic('medium');
    if (result) {
       setQuery(result.mainTranslation);
       handleSearch(result.mainTranslation, prevTarget, prevSource);
    }
  };

  useEffect(() => {
    const handleDocumentClick = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      const isInteraction = target.closest('button') || target.closest('a') || target.closest('select');
      const isInput = target === inputRef.current;
      const isResult = target.closest('.result-container');
      if (!isInteraction && !isInput && !isResult && inputRef.current) {
        setTimeout(() => inputRef.current?.focus(), 0);
      }
    };
    document.addEventListener('mousedown', handleDocumentClick);
    return () => document.removeEventListener('mousedown', handleDocumentClick);
  }, []);

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) setVoiceSupported(false);
  }, []);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      setShowSuggestions(false);
      localStorage.setItem('lexSourceLang', selectedEntry.sourceLang);
      localStorage.setItem('lexTargetLang', selectedEntry.targetLang);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    if (loading) {
      setShowSuggestions(false);
      setSuggestions([]);
      return;
    }
    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      if (trimmedQuery.length >= 2) {
        const normSearch = normalizeQuery(trimmedQuery, sourceLang);
        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && normalizeQuery(e.term, e.sourceLang).startsWith(normSearch))
          .map(e => ({ term: e.term, source: 'local' as const }));
        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && normalizeQuery(e.term, sourceLang).startsWith(normSearch))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));
        let globalMatches: SuggestionItem[] = [];
        try {
          const globalTerms = await fetchSuggestions(query, sourceLang);
          globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));
        } catch (e) {}
        const combined = [...localMatches, ...seedMatches, ...globalMatches];
        const unique = combined.filter((v, i, a) => 
          a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
        ).slice(0, 8);
        if (!loading && !(result && result.term.toLowerCase() === query.trim().toLowerCase())) {
          setSuggestions(unique);
          setShowSuggestions(unique.length > 0);
          setSelectedIndex(-1);
        }
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 150);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history, loading, result]);

  const handleSearch = async (overrideQuery?: string, sLang: Language = sourceLang, tLang: Language = targetLang) => {
    await resumeAudioContext().catch(() => {});
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    // Strict block for same-language translation
    if (sLang === tLang) {
      setSearchError("Philological discovery requires distinct languages. (e.g., German to Uzbek)");
      triggerHaptic('error');
      return;
    }

    setShowSuggestions(false);
    setSearchError(null);
    setQuery(cleanQuery);

    const normQuery = normalizeQuery(cleanQuery, sLang);
    const localHit = history.find(e => normalizeQuery(e.term, e.sourceLang) === normQuery && e.sourceLang === sLang && e.targetLang === tLang);

    if (localHit) {
      setResult(localHit);
      if (autoAudio) {
        speak(cleanQuery, sLang).then(() => speak(localHit.mainTranslation, tLang)).catch(() => {});
      }
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      // OPTIMIZATION: Start DB Check and AI Core Translation simultaneously (Optimistic Parallelism)
      const dbPromise = fetchGlobalEntry(normQuery, sLang, tLang);
      const aiPromise = translateWordCore(cleanQuery, sLang, tLang);

      // We wait for DB first as it's faster, but AI is already warm
      const globalHit = await dbPromise;
      if (globalHit) {
        setResult(globalHit);
        onEntrySaved(globalHit);
        setLoading(false);
        if (autoAudio) {
          speak(cleanQuery, sLang).then(() => speak(globalHit.mainTranslation, tLang)).catch(() => {});
        }
        return;
      }

      // If DB fails, AI is likely already processing. Total time is max(DB, AI) instead of sum(DB, AI)
      const coreEntry = await aiPromise;
      coreEntry.normalizedTerm = normQuery;

      setResult(coreEntry);
      setLoading(false);

      if (autoAudio) {
        speak(cleanQuery, sLang).then(() => speak(coreEntry.mainTranslation, tLang)).catch(() => {});
      }

      // Enrich in background
      enrichLexicalEntry(cleanQuery, sLang, tLang).then(enrichment => {
        const fullEntry = { ...coreEntry, ...enrichment };
        setResult(fullEntry);
        onEntrySaved(fullEntry);
        saveGlobalEntry(fullEntry);
      }).catch(e => console.error("Enrichment failed", e));

    } catch (err: any) {
      setSearchError(err.message === "Invalid Philological Record Structure" 
        ? "The inscription structure was corrupted during retrieval." 
        : "The archive is silent. Network connectivity or API limits reached.");
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      setShowSuggestions(false);
      if (showSuggestions && selectedIndex >= 0) {
        const selectedTerm = suggestions[selectedIndex].term;
        setQuery(selectedTerm);
        handleSearch(selectedTerm);
      } else {
        handleSearch();
      }
      return;
    }
    if (!showSuggestions && e.key === 'Escape') { inputRef.current?.blur(); return; }
    if (showSuggestions) {
      if (e.key === 'ArrowDown') { e.preventDefault(); setSelectedIndex(prev => (prev + 1) % suggestions.length); }
      else if (e.key === 'ArrowUp') { e.preventDefault(); setSelectedIndex(prev => (prev - 1 + suggestions.length) % suggestions.length); }
      else if (e.key === 'Escape') { setShowSuggestions(false); }
    }
  };

  return (
    <div className="space-y-8 md:space-y-16 max-w-7xl mx-auto contain-layout">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-8 pt-4">
        <div className="flex items-center gap-6">
          <div className="space-y-1 border-l-[3px] border-[#7c1a1a] pl-4">
            <span className="text-[9px] uppercase tracking-[0.4em] text-stone-500 font-black">Philological Mastery</span>
            <div className="flex items-baseline gap-2">
              <span className="text-2xl md:text-3xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
              <span className="text-[8px] uppercase tracking-[0.2em] text-stone-400 font-bold">Total XP</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-8 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-2 bg-stone-100/50 p-1.5 rounded-sm w-full sm:w-auto border border-stone-200">
             <div className="grid grid-cols-5 bg-white shadow-md overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-200">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} onClick={() => updateSourceLang(full)} className={`px-4 py-3 text-[10px] sm:text-[11px] font-black tracking-widest transition-colors ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-400 hover:text-stone-700'}`}>
                    {short}
                  </button>
                ))}
             </div>

             <button 
               onClick={swapLanguages} 
               className="p-3 bg-white hover:bg-stone-50 text-stone-400 hover:text-[#7c1a1a] transition-all rounded-sm shadow-md border border-stone-200 group active:scale-95"
               title="Swap Languages"
             >
               <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="group-hover:rotate-180 transition-transform duration-500">
                 <path d="M7 10l5-5 5 5"/><path d="M17 14l-5 5-5-5"/>
               </svg>
             </button>

             <div className="grid grid-cols-5 bg-white shadow-md overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-200">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} onClick={() => updateTargetLang(full)} className={`px-4 py-3 text-[10px] sm:text-[11px] font-black tracking-widest transition-colors ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-400 hover:text-stone-700'}`}>
                    {short}
                  </button>
                ))}
             </div>
          </div>
          <button onClick={() => { setAutoAudio(!autoAudio); triggerHaptic('light'); }} className={`flex items-center gap-4 px-5 py-2.5 rounded-full border transition-all ${autoAudio ? 'bg-[#7c1a1a]/5 border-[#7c1a1a]/40' : 'bg-stone-50 border-stone-200'}`}>
            <span className={`text-[11px] uppercase tracking-[0.2em] font-black ${autoAudio ? 'text-[#7c1a1a]' : 'text-stone-500'}`}>AUTO-AUDIO</span>
            <div className={`w-3.5 h-3.5 rounded-full ${autoAudio ? 'bg-[#7c1a1a] shadow-[0_0_10px_rgba(124,26,26,0.4)]' : 'bg-stone-300'}`} />
          </button>
        </div>
      </div>

      <div className="relative w-full">
        <form onSubmit={(e) => { e.preventDefault(); handleSearch(); }}>
          <div className={`bg-white border-2 transition-all rounded-sm overflow-hidden flex items-stretch min-h-[70px] md:min-h-[110px] ${isListening ? 'border-[#7c1a1a] ring-8 ring-[#7c1a1a]/5' : 'border-stone-200 shadow-md focus-within:border-stone-400 focus-within:shadow-lg'}`}>
            <input 
              ref={inputRef}
              type="text" 
              value={query} 
              onChange={(e) => setQuery(e.target.value)} 
              onFocus={() => { if (suggestions.length > 0 && !loading) setShowSuggestions(true); }}
              onKeyDown={handleKeyDown}
              spellCheck={false}
              autoCapitalize="none"
              autoComplete="off"
              autoCorrect="off"
              placeholder={isListening ? "Listening..." : voiceStatusMsg || "Summon an inscription..."}
              className={`flex-1 min-w-0 px-6 md:px-10 text-2xl md:text-6xl serif bg-transparent outline-none text-stone-900 lowercase transition-all ${isListening ? 'placeholder:text-[#7c1a1a]/40' : voiceStatusMsg ? 'placeholder:text-[#7c1a1a]' : 'placeholder:text-stone-200'}`} 
            />
            <div className="flex flex-shrink-0 items-stretch border-l-2 border-stone-50">
              <button 
                type="button" 
                onMouseDown={(e) => e.preventDefault()}
                onClick={async () => {
                  await resumeAudioContext().catch(() => {});
                  const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
                  if (!SpeechRecognition) { setVoiceStatusMsg("Voice restricted"); triggerHaptic('error'); setTimeout(() => setVoiceStatusMsg(null), 3000); return; }
                  const recognition = new SpeechRecognition();
                  const langCodes: Record<Language, string> = { German: 'de-DE', Uzbek: 'uz-UZ', English: 'en-US', Russian: 'ru-RU', Arabic: 'ar-SA' };
                  recognition.lang = langCodes[sourceLang];
                  recognition.onstart = () => { setIsListening(true); triggerHaptic('light'); };
                  recognition.onresult = (event: any) => { const transcript = event.results[0][0].transcript; setQuery(transcript); handleSearch(transcript); };
                  recognition.onerror = () => setIsListening(false);
                  recognition.onend = () => setIsListening(false);
                  try { recognition.start(); } catch (e) { setIsListening(false); }
                }}
                className={`px-4 md:px-8 transition-all flex items-center justify-center border-r border-stone-50 ${isListening ? 'text-[#7c1a1a] bg-[#7c1a1a]/5' : !voiceSupported ? 'text-stone-200 cursor-not-allowed' : 'text-stone-400 hover:text-[#7c1a1a]'}`}
              >
                <div className="relative">
                  {isListening && <div className="absolute -inset-2 border-2 border-[#7c1a1a]/20 rounded-full animate-ping"></div>}
                  <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 md:w-9 md:h-9" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" x2="12" y1="19" y2="22"/></svg>
                </div>
              </button>
              <button type="submit" disabled={loading} onMouseDown={(e) => e.preventDefault()} className={`px-5 md:px-10 transition-all flex items-center justify-center ${loading ? 'bg-stone-50' : 'bg-white hover:bg-[#7c1a1a]/5 text-[#7c1a1a]'}`}>
                {loading ? <div className="w-8 h-8 border-4 border-[#7c1a1a] border-t-transparent rounded-full animate-spin" /> : <svg xmlns="http://www.w3.org/2000/svg" className="w-8 h-8 md:w-12 md:h-12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"><line x1="5" y1="12" x2="19" y2="12"></line><polyline points="12 5 19 12 12 19"></polyline></svg>}
              </button>
            </div>
          </div>
        </form>
        {showSuggestions && !loading && (
          <div className="absolute top-full left-0 right-0 bg-white border-2 border-stone-200 shadow-2xl z-20 rounded-b-sm overflow-hidden animate-in fade-in slide-in-from-top-2">
             {suggestions.map((s, idx) => (
               <button key={idx} onMouseDown={(e) => e.preventDefault()} onClick={() => { setQuery(s.term); handleSearch(s.term); }} className={`w-full text-left px-10 py-6 border-b border-stone-100 last:border-0 flex items-center justify-between transition-colors ${selectedIndex === idx ? 'bg-stone-50' : 'hover:bg-stone-50/50'}`}>
                 <span className="serif text-2xl md:text-3xl text-stone-700">{s.term}</span>
                 <span className="text-[9px] uppercase tracking-widest font-black text-stone-300">{s.source}</span>
               </button>
             ))}
          </div>
        )}
      </div>

      <div className="min-h-[60px] result-container">
        {loading && (
          <div className="bg-white border border-stone-100 p-16 flex flex-col items-center justify-center space-y-8">
            <div className="w-20 h-20 border-[5px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin"></div>
            <p className="serif text-3xl italic text-stone-300">Consulting the Lexicon...</p>
          </div>
        )}
        {searchError && (
          <div className="bg-[#7c1a1a] text-stone-100 p-12 md:p-20 rounded-sm shadow-xl animate-in zoom-in-95 duration-500">
             <div className="flex flex-col md:flex-row items-center gap-8">
                <div className="p-6 bg-white/10 rounded-full"><svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg></div>
                <div className="flex-1 text-center md:text-left">
                  <h3 className="text-3xl md:text-5xl serif font-black mb-4">The Archive is Silent.</h3>
                  <p className="text-stone-300 serif italic text-xl md:text-2xl mb-8 opacity-80">{searchError}</p>
                  <button onClick={() => handleSearch()} onMouseDown={(e) => e.preventDefault()} className="px-10 py-4 bg-white text-[#7c1a1a] text-[11px] font-black uppercase tracking-[0.4em] hover:bg-stone-100 transition-all rounded-sm shadow-lg active:scale-95">Retry Invocation</button>
                </div>
             </div>
          </div>
        )}
        {result && <ResultCard entry={result} onSearchTerm={(term) => handleSearch(term)} />}
      </div>

      <div className="pt-16 md:pt-32 border-t border-stone-100">
        <div className="flex justify-between items-center mb-12">
          <div className="border-l-[4px] border-[#7c1a1a] pl-8 py-1">
            <h2 className="text-[14px] uppercase tracking-[0.6em] text-stone-900 font-black">Archival Chronicles</h2>
          </div>
        </div>
        <HistoryGrid history={history} onEntryClick={onEntryClick} />
      </div>
    </div>
  );
};

export default Dictionary;

import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";

const generateId = () => {
  try {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID();
    }
  } catch (e) {}
  return 'lex-' + Date.now() + '-' + Math.random().toString(36).substring(2, 11);
};

function cleanJsonResponse(text: string): string {
  if (!text) return "{}";
  let cleaned = text.trim();
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  const firstBracket = cleaned.indexOf('[');
  const lastBracket = cleaned.lastIndexOf(']');
  let start = -1;
  let end = -1;
  if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
    start = firstBrace;
    end = lastBrace;
  } else if (firstBracket !== -1) {
    start = firstBracket;
    end = lastBracket;
  }
  if (start !== -1 && end !== -1 && end > start) {
    cleaned = cleaned.substring(start, end + 1);
  }
  if (cleaned.startsWith("```")) {
    cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/, "").replace(/\n?```$/, "");
  }
  return cleaned.trim();
}

function shuffleArray<T>(array: T[]): T[] {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
}

/**
 * PHASE 1: Optimized Core Translation
 * Streamlined prompt for lowest latency.
 */
export async function translateWordCore(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // High-speed optimized prompt: minimal instruction
  const prompt = `Translate "${query}" (${sourceLanguage} -> ${targetLanguage}). 
MANDATORY: ${targetLanguage} MUST be different from ${sourceLanguage}. 
Output JSON ONLY.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      thinkingConfig: { thinkingBudget: 0 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          term: { type: Type.STRING },
          mainTranslation: { type: Type.STRING },
          partOfSpeech: { type: Type.STRING },
          gender: { type: Type.STRING },
          plural: { type: Type.STRING },
          cefrLevel: { type: Type.STRING },
          synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
          variations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                confidence: { type: Type.NUMBER }
              }
            }
          }
        },
        required: ["term", "mainTranslation", "partOfSpeech"]
      }
    }
  });

  const text = response.text || "{}";
  const cleaned = cleanJsonResponse(text);

  try {
    const rawData = JSON.parse(cleaned);
    return {
      id: generateId(),
      term: rawData.term || query,
      normalizedTerm: query.toLowerCase().trim(),
      mainTranslation: rawData.mainTranslation,
      sourceLang: sourceLanguage,
      targetLang: targetLanguage,
      cefrLevel: sourceLanguage !== 'Uzbek' ? rawData.cefrLevel : undefined,
      philology: {
        etymology: "", 
        partOfSpeech: rawData.partOfSpeech,
        gender: rawData.gender,
        plural: rawData.plural
      },
      culture: { usage: "", register: 'neutral', notes: "" },
      synonyms: rawData.synonyms || [],
      variations: (rawData.variations || []).map((v: any) => ({ ...v, source: 'ai' })),
      literature: [],
      realLifeSentences: [],
      idioms: [],
      timestamp: Date.now()
    };
  } catch (err) {
    throw new Error("Invalid Philological Record Structure");
  }
}

/**
 * PHASE 2: Independent Archival Enrichment
 */
export async function enrichLexicalEntry(term: string, sourceLang: Language, targetLang: Language): Promise<Partial<LexicalEntry>> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Deeply enrich philological record for "${term}".
Source: ${sourceLang}, Target: ${targetLang}. 
Quotes max 15 words. Output JSON ONLY.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        systemInstruction: "Concise Philologist. Quotes < 15 words.",
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            etymology: { type: Type.STRING },
            usage: { type: Type.STRING },
            register: { type: Type.STRING },
            notes: { type: Type.STRING },
            literature: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  source: { type: Type.STRING },
                  author: { type: Type.STRING }
                }
              }
            },
            idioms: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  context: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });

    const cleaned = cleanJsonResponse(response.text || "{}");
    const raw = JSON.parse(cleaned);

    return {
      philology: { etymology: raw.etymology || "Archival verification complete.", partOfSpeech: "" },
      culture: {
        usage: raw.usage || "",
        register: raw.register || 'neutral',
        notes: raw.notes || ""
      },
      literature: raw.literature || [],
      realLifeSentences: raw.idioms || [], 
      idioms: raw.idioms || []
    };
  } catch (err) {
    return {
      philology: { etymology: "Archival record verified.", partOfSpeech: "" }
    };
  }
}

export async function getDailyInsight() {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = "Short linguistic fact. JSON ONLY.";
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            fact: { type: Type.STRING }
          }
        }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (err) {
    return { title: "Lexical Continuity", fact: "Language is the vessel of human history." };
  }
}

export async function generateQuiz(entries: LexicalEntry[]) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const context = entries.map(e => `${e.term} -> ${e.mainTranslation}`).join(", ");
  const prompt = `Quiz for: ${context}. 3 choices. JSON Array.`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              correctAnswer: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              explanation: { type: Type.STRING }
            },
            required: ["question", "correctAnswer", "options", "explanation"]
          }
        }
      }
    });
    const cleaned = cleanJsonResponse(response.text || "[]");
    const questions = JSON.parse(cleaned);
    return questions.map((q: any) => ({
      ...q,
      options: shuffleArray(q.options)
    }));
  } catch (err) {
    return [];
  }
}
